#include <iostream>
#include <vector>

std::vector<int> memo;

int a(int n) {
    if (n == 0 || n == 1) return 1;
    if (memo[n] != -1) return memo[n];
    if (n % 2 == 0) {
        int half = n / 2;
        return memo[n] = a(half) + a(half - 1);
    } else {
        int half = n / 2;
        return memo[n] = a(half) - a(half - 1);
    }
}

int main() {
    int n;
    std::cin >> n;
    memo.assign(n + 1, -1);
    std::cout << a(n) << std::endl;
    return 0;
}
